1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should let a single live cell die from underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should let two live cells die from underpopulation", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block still life unchanged (survival with 2 or 3 neighbors)", () => {
15	    const block = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should let a live cell with more than 3 neighbors die from overpopulation", () => {
21	    const plus = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
22	    const result = nextGeneration(plus);
23	    expect(result).toEqual(expect.not.arrayContaining([[1, 1]]));
24	  });
25	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
26	    const lTromino = [[0, 0], [1, 0], [0, 1]];
27	    const result = nextGeneration(lTromino);
28	    expect(result).toEqual(
29	      expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]),
30	    );
31	  });
32	  it.todo("should evolve a blinker from vertical to horizontal");
33	});
