1	type Cell = number[];
2	
3	function sameCell(a: Cell, b: Cell): boolean {
4	  return a[0] === b[0] && a[1] === b[1];
5	}
6	
7	function isNeighbor(a: Cell, b: Cell): boolean {
8	  return (
9	    !sameCell(a, b) && Math.abs(a[0] - b[0]) <= 1 && Math.abs(a[1] - b[1]) <= 1
10	  );
11	}
12	
13	function countLiveNeighbors(cell: Cell, liveCells: Cell[]): number {
14	  return liveCells.filter((other) => isNeighbor(cell, other)).length;
15	}
16	
17	function isLive(cell: Cell, liveCells: Cell[]): boolean {
18	  return liveCells.some((other) => sameCell(other, cell));
19	}
20	
21	function candidateCells(liveCells: Cell[]): Cell[] {
22	  const candidates: Cell[] = [];
23	  for (const cell of liveCells) {
24	    for (let dx = -1; dx <= 1; dx++) {
25	      for (let dy = -1; dy <= 1; dy++) {
26	        const candidate: Cell = [cell[0] + dx, cell[1] + dy];
27	        if (!isLive(candidate, candidates)) {
28	          candidates.push(candidate);
29	        }
30	      }
31	    }
32	  }
33	  return candidates;
34	}
35	
36	export function nextGeneration(liveCells: Cell[]): Cell[] {
37	  return candidateCells(liveCells).filter((cell) => {
38	    const liveNeighbors = countLiveNeighbors(cell, liveCells);
39	    if (isLive(cell, liveCells)) {
40	      return liveNeighbors === 2 || liveNeighbors === 3;
41	    }
42	    return liveNeighbors === 3;
43	  });
44	}
